/** Calendar system (plan M23) — Fantasy calendar with 12 named Czech months,
 * 4 seasons, 360-day years. Pure functions — no DB/Tauri imports — so they're
 * unit-testable in isolation.
 *
 * Each year has exactly 360 days: 12 months × 30 days.
 * Each season spans 90 days (3 months).
 *
 * Month names use Czech genitive forms for date formatting
 * (e.g. "15. Jarního větru, Rok 847"). */

export interface CalendarDate {
  year: number;
  /** 1-based day of year (1..360). */
  dayOfYear: number;
  month: string;
  /** 1-based day within the current month (1..30). */
  day: number;
  season: string;
}

// ---- Month definitions ---------------------------------------------------

export interface MonthDef {
  name: string;
  genitive: string;
  days: number;
  season: string;
}

/** 12 Czech fantasy months, 30 days each, grouped by season. */
export const MONTHS: MonthDef[] = [
  // Jaro (Spring) — days 1–90
  { name: "Měsíc probuzení",  genitive: "Měsíce probuzení",  days: 30, season: "Jaro" },
  { name: "Jarní vítr",       genitive: "Jarního větru",      days: 30, season: "Jaro" },
  { name: "Měsíc květů",      genitive: "Měsíce květů",       days: 30, season: "Jaro" },
  // Léto (Summer) — days 91–180
  { name: "Měsíc slunce",     genitive: "Měsíce slunce",      days: 30, season: "Léto" },
  { name: "Měsíc žáru",       genitive: "Měsíce žáru",        days: 30, season: "Léto" },
  { name: "Měsíc bouří",      genitive: "Měsíce bouří",       days: 30, season: "Léto" },
  // Podzim (Autumn) — days 181–270
  { name: "Měsíc sklizně",    genitive: "Měsíce sklizně",     days: 30, season: "Podzim" },
  { name: "Měsíc listí",      genitive: "Měsíce listí",       days: 30, season: "Podzim" },
  { name: "Měsíc mlh",        genitive: "Měsíce mlh",         days: 30, season: "Podzim" },
  // Zima (Winter) — days 271–360
  { name: "Měsíc mrazu",      genitive: "Měsíce mrazu",       days: 30, season: "Zima" },
  { name: "Měsíc sněhu",      genitive: "Měsíce sněhu",       days: 30, season: "Zima" },
  { name: "Měsíc temnoty",    genitive: "Měsíce temnoty",     days: 30, season: "Zima" },
];

/** Total days in a calendar year. */
export const DAYS_PER_YEAR = 360;

// ---- Season effects (prompt only, no mechanics) -------------------------

export const SEASON_EFFECTS: Record<string, string> = {
  "Jaro":   "Příroda se probouzí. Cesty jsou blátivé. Bylinky raší.",
  "Léto":   "Horké dny. Obchodníci jsou na cestách. Bouřky jsou časté.",
  "Podzim": "Sklizeň. Listí padá. Lovná zvěř je aktivní.",
  "Zima":   "Mráz. Sníh. Cesty jsou nebezpečné. Noci dlouhé.",
};

// ---- Core functions -------------------------------------------------------

/** Returns the Czech season name for a given day-of-year (1..360).
 * Clamps out-of-range values to the nearest valid season. */
export function getSeason(dayOfYear: number): string {
  const d = Math.max(1, Math.min(DAYS_PER_YEAR, Math.floor(dayOfYear)));
  if (d <= 90) return "Jaro";
  if (d <= 180) return "Léto";
  if (d <= 270) return "Podzim";
  return "Zima";
}

/** Builds a CalendarDate from a year and day-of-year. */
export function calendarDateFromDays(year: number, dayOfYear: number): CalendarDate {
  const d = Math.max(1, Math.min(DAYS_PER_YEAR, Math.floor(dayOfYear)));
  let remaining = d;
  let monthIdx = 0;
  for (let i = 0; i < MONTHS.length; i++) {
    if (remaining <= MONTHS[i].days) {
      monthIdx = i;
      break;
    }
    remaining -= MONTHS[i].days;
  }
  const month = MONTHS[monthIdx];
  return {
    year,
    dayOfYear: d,
    month: month.genitive,
    day: remaining,
    season: month.season,
  };
}

/** Default calendar start: 1. Měsíce probuzení, Rok 847 (day 1 of year 847). */
export function defaultCalendarDate(): CalendarDate {
  return calendarDateFromDays(847, 1);
}

/** Advances the calendar by one day, wrapping year boundaries. */
export function advanceDay(current: CalendarDate): CalendarDate {
  const nextDay = current.dayOfYear >= DAYS_PER_YEAR ? 1 : current.dayOfYear + 1;
  const nextYear = current.dayOfYear >= DAYS_PER_YEAR ? current.year + 1 : current.year;
  return calendarDateFromDays(nextYear, nextDay);
}

/** Formats a CalendarDate for display: "15. Jarního větru, Rok 847". */
export function formatCalendarDate(date: CalendarDate): string {
  return `${date.day}. ${date.month}, Rok ${date.year}`;
}

/** Short format for UI header: "📅 15. Jarního větru, 847". */
export function formatCalendarDateShort(date: CalendarDate): string {
  return `📅 ${date.day}. ${date.month}, ${date.year}`;
}

/** Produces the full prompt block for the current date including season effects
 * and the `[TIME:+1d]` tag instruction for advancing the calendar. */
export function calendarDescription(date: CalendarDate): string {
  const effects = SEASON_EFFECTS[date.season] ?? "";
  const tagNote = "Pro posun času o jeden den použij tag [TIME:+1d] — spustí se efekty úsvitu/soumraku.";
  return `[DNEŠNÍ DATUM] ${formatCalendarDate(date)} (${date.season})\n${effects}\n${tagNote}`;
}

/** Serializes calendar state to a storable JSON object. */
export function calendarToJSON(date: CalendarDate): { year: number; dayOfYear: number } {
  return { year: date.year, dayOfYear: date.dayOfYear };
}

/** Deserializes calendar state from stored JSON. Falls back to default on any error. */
export function calendarFromJSON(json: unknown): CalendarDate {
  try {
    const obj = json as Record<string, unknown>;
    if (typeof obj?.year === "number" && typeof obj?.dayOfYear === "number") {
      return calendarDateFromDays(obj.year, obj.dayOfYear);
    }
  } catch {
    // fall through
  }
  return defaultCalendarDate();
}

import { execute, query } from "../database";

interface SettingRow {
  key: string;
  value: string;
}

export async function getSetting(key: string): Promise<string | null> {
  const rows = await query<SettingRow>("SELECT key, value FROM settings WHERE key = $1", [key]);
  return rows[0]?.value ?? null;
}

export async function setSetting(key: string, value: string): Promise<void> {
  await execute(
    `INSERT INTO settings (key, value) VALUES ($1, $2)
     ON CONFLICT (key) DO UPDATE SET value = excluded.value`,
    [key, value],
  );
}

export async function resetAllSettings(): Promise<void> {
  await execute("DELETE FROM settings", []);
}

export async function getAllSettings(): Promise<Record<string, string>> {
  const rows = await query<SettingRow>("SELECT key, value FROM settings", []);
  return Object.fromEntries(rows.map((r) => [r.key, r.value]));
}

// ---- Log level (tiered logging) ------------------------------------------

export type LogLevel = "debug" | "info" | "warn" | "error";

const LOG_LEVEL_SETTING_KEY = "log_level";
const LOG_LEVELS: readonly LogLevel[] = ["debug", "info", "warn", "error"];

function isLogLevel(value: string): value is LogLevel {
  return (LOG_LEVELS as readonly string[]).includes(value);
}

/** Reads the configured minimum log level, or `null` if never set (callers
 *  should fall back to the default, `"info"`). */
export async function getLogLevel(): Promise<LogLevel | null> {
  const raw = await getSetting(LOG_LEVEL_SETTING_KEY);
  if (raw && isLogLevel(raw)) return raw;
  return null;
}

/** Persists the configured minimum log level. */
export async function setLogLevel(level: LogLevel): Promise<void> {
  await setSetting(LOG_LEVEL_SETTING_KEY, level);
}

// ---- Calendar helpers (plan M23) ----------------------------------------

export const CALENDAR_SETTING_KEY = "game_calendar";

export interface CalendarJSON {
  year: number;
  dayOfYear: number;
}

/** Reads the stored calendar for a chat, or returns null if never set. */
export async function getCalendarSetting(chatId: string): Promise<CalendarJSON | null> {
  const key = `${CALENDAR_SETTING_KEY}_${chatId}`;
  const raw = await getSetting(key);
  if (!raw) return null;
  try {
    const parsed = JSON.parse(raw) as CalendarJSON;
    if (typeof parsed.year === "number" && typeof parsed.dayOfYear === "number") {
      return parsed;
    }
  } catch {
    // fall through
  }
  return null;
}

/** Persists the calendar JSON for a chat. */
export async function setCalendarSetting(chatId: string, cal: CalendarJSON): Promise<void> {
  const key = `${CALENDAR_SETTING_KEY}_${chatId}`;
  await setSetting(key, JSON.stringify(cal));
}

// ---- Sync helpers (M14) -------------------------------------------------

/** Generates and stores a random device-id the first time sync is enabled.
 *  Returns the existing device-id if one is already stored. */
export async function ensureDeviceId(): Promise<string> {
  const existing = await getSetting("device_id");
  if (existing) return existing;
  const id = crypto.randomUUID();
  await setSetting("device_id", id);
  return id;
}

export interface SyncPosition {
  file: string;
  byteOffset: number;
}

/** Reads tracked sync positions (which byte of each foreign journal file has
 *  already been processed). Returns an empty array when nothing is tracked. */
export async function getSyncPositions(): Promise<SyncPosition[]> {
  const raw = await getSetting("sync_positions");
  if (!raw) return [];
  try {
    const parsed = JSON.parse(raw);
    if (!Array.isArray(parsed)) return [];
    return parsed.filter(
      (p: unknown): p is SyncPosition =>
        typeof p === "object" && p !== null &&
        typeof (p as SyncPosition).file === "string" &&
        typeof (p as SyncPosition).byteOffset === "number",
    );
  } catch {
    return [];
  }
}

/** Persists the current sync positions. */
export async function setSyncPositions(positions: SyncPosition[]): Promise<void> {
  await setSetting("sync_positions", JSON.stringify(positions));
}

import { execute, newId, nowIso, query } from "../database";
import { journalEntityWrite } from "../syncJournal";

export type QuestStatus = "active" | "completed" | "failed";

export interface Quest {
  id: string;
  chatId: string;
  name: string;
  description: string;
  status: QuestStatus;
  createdAt: string;
  updatedAt: string;
}

interface QuestRow {
  id: string;
  chat_id: string;
  name: string;
  description: string;
  status: string;
  created_at: string;
  updated_at: string;
}

function toQuest(row: QuestRow): Quest {
  return {
    id: row.id,
    chatId: row.chat_id,
    name: row.name,
    description: row.description,
    status: row.status as QuestStatus,
    createdAt: row.created_at,
    updatedAt: row.updated_at,
  };
}

/** List all quests for a chat, active first, then completed, then failed. */
export async function listQuests(chatId: string): Promise<Quest[]> {
  const rows = await query<QuestRow>(
    `SELECT * FROM quests WHERE chat_id = $1
     ORDER BY CASE status
       WHEN 'active' THEN 0
       WHEN 'completed' THEN 1
       WHEN 'failed' THEN 2
     END, created_at ASC`,
    [chatId],
  );
  return rows.map(toQuest);
}

/** Get a single quest by name within a chat (for upsert logic). */
export async function getQuestByName(
  chatId: string,
  name: string,
): Promise<Quest | null> {
  const rows = await query<QuestRow>(
    "SELECT * FROM quests WHERE chat_id = $1 AND name = $2",
    [chatId, name],
  );
  return rows[0] ? toQuest(rows[0]) : null;
}

export interface CreateQuestInput {
  chatId: string;
  name: string;
  description?: string;
}

/** Create a new quest (active by default). */
export async function createQuest(input: CreateQuestInput): Promise<Quest> {
  const id = newId();
  const now = nowIso();
  await execute(
    `INSERT INTO quests (id, chat_id, name, description, status, created_at, updated_at)
     VALUES ($1, $2, $3, $4, 'active', $5, $5)`,
    [id, input.chatId, input.name, input.description ?? "", now],
  );
  const quest: Quest = {
    id,
    chatId: input.chatId,
    name: input.name,
    description: input.description ?? "",
    status: "active",
    createdAt: now,
    updatedAt: now,
  };
  journalEntityWrite("quest", quest as unknown as Record<string, unknown>);
  return quest;
}

/** Update a quest's status (active / completed / failed). */
export async function updateQuestStatus(
  id: string,
  status: QuestStatus,
): Promise<void> {
  const now = nowIso();
  await execute(
    "UPDATE quests SET status = $2, updated_at = $3 WHERE id = $1",
    [id, status, now],
  );
  journalEntityWrite("quest", { id, status, updated_at: now });
}

/** Append a progress note to the quest description. */
export async function addQuestNote(id: string, note: string): Promise<void> {
  const now = nowIso();
  await execute(
    `UPDATE quests SET
       description = CASE
         WHEN description = '' THEN $2
         ELSE description || '\n' || $2
       END,
       updated_at = $3
     WHERE id = $1`,
    [id, note, now],
  );
  journalEntityWrite("quest", { id, _note: note, updated_at: now });
}

import Database from "@tauri-apps/plugin-sql";

const DB_URL = "sqlite:mysillytavern.db";
const CACHE_TTL = 5_000; // 5 seconds

let dbPromise: Promise<Database> | null = null;

/** Lazily opens (and caches) the single SQLite connection for the app. */
export function getDb(): Promise<Database> {
  if (!dbPromise) {
    dbPromise = Database.load(DB_URL);
  }
  return dbPromise;
}

// -- Query cache --
const cache = new Map<string, { data: unknown; expires: number }>();

function cacheKey(sql: string, params: unknown[]): string {
  return `${sql}|${JSON.stringify(params)}`;
}

/** Clear the entire cache. Called after any write (execute). */
export function invalidateCache(): void {
  cache.clear();
}

export async function query<T>(sql: string, params: unknown[] = []): Promise<T[]> {
  const key = cacheKey(sql, params);
  const entry = cache.get(key);
  if (entry && entry.expires > Date.now()) {
    return entry.data as T[];
  }
  const db = await getDb();
  const result = await db.select<T[]>(sql, params);
  cache.set(key, { data: result, expires: Date.now() + CACHE_TTL });
  return result;
}

export async function execute(sql: string, params: unknown[] = []): Promise<void> {
  const db = await getDb();
  await db.execute(sql, params);
  // Any write invalidates the entire cache — simple and safe
  cache.clear();
}

export function newId(): string {
  return crypto.randomUUID();
}

export function nowIso(): string {
  return new Date().toISOString();
}

import { create } from "zustand";

import {
  createChat,
  deleteChat,
  listChats,
  renameChat,
  setChatConnection,
  setChatPersona,
  setChatPreset,
  setExtractionConnection,
  type Chat,
  type ChatDraft,
} from "../db/repositories/chatsRepo";

interface ChatListState {
  chats: Chat[];
  loaded: boolean;
  load: () => Promise<void>;
  create: (draft: ChatDraft) => Promise<Chat>;
  rename: (id: string, title: string) => Promise<void>;
  setConnection: (id: string, connectionId: string | null) => Promise<void>;
  setPersona: (id: string, personaId: string | null) => Promise<void>;
  setPreset: (id: string, presetId: string | null) => Promise<void>;
  setExtractionConnection: (id: string, connectionId: string | null) => Promise<void>;
  remove: (id: string) => Promise<void>;
}

export const useChatListStore = create<ChatListState>((set, get) => ({
  chats: [],
  loaded: false,

  load: async () => {
    const chats = await listChats();
    set({ chats, loaded: true });
  },

  create: async (draft) => {
    const created = await createChat(draft);
    set({ chats: [created, ...get().chats] });
    return created;
  },

  rename: async (id, title) => {
    await renameChat(id, title);
    set({ chats: get().chats.map((c) => (c.id === id ? { ...c, title } : c)) });
  },

  setConnection: async (id, connectionId) => {
    await setChatConnection(id, connectionId);
    set({ chats: get().chats.map((c) => (c.id === id ? { ...c, connectionId } : c)) });
  },

  setPersona: async (id, personaId) => {
    await setChatPersona(id, personaId);
    set({ chats: get().chats.map((c) => (c.id === id ? { ...c, personaId } : c)) });
  },

  setPreset: async (id, presetId) => {
    await setChatPreset(id, presetId);
    set({ chats: get().chats.map((c) => (c.id === id ? { ...c, presetId } : c)) });
  },

  setExtractionConnection: async (id, connectionId) => {
    await setExtractionConnection(id, connectionId);
    set({
      chats: get().chats.map((c) => (c.id === id ? { ...c, extractionConnectionId: connectionId } : c)),
    });
  },

  remove: async (id) => {
    await deleteChat(id);
    set({ chats: get().chats.filter((c) => c.id !== id) });
  },
}));

import { useState, useCallback } from "react";
import { useNavigate } from "react-router-dom";
import { useAndroidBack } from "../useAndroidBack";

export type PanelType =
  | "memory"
  | "inventory"
  | "quests"
  | "director"
  | "character"
  | "group"
  | "export";

/**
 * Manages the mutually-exclusive header panel state (memory, inventory,
 * quests, director, character, group, export). Opening one panel closes any
 * other that was open.
 *
 * Also wires the Android back button to close panels before navigating away.
 */
export function useChatPanels() {
  const navigate = useNavigate();
  const [activePanel, setActivePanel] = useState<PanelType | null>(null);

  const openPanel = useCallback((panel: PanelType) => setActivePanel(panel), []);
  const closePanel = useCallback(() => setActivePanel(null), []);
  const togglePanel = useCallback(
    (panel: PanelType) => setActivePanel((p) => (p === panel ? null : panel)),
    [],
  );

  // Convenience booleans
  const memoryOpen = activePanel === "memory";
  const inventoryOpen = activePanel === "inventory";
  const questsOpen = activePanel === "quests";
  const directorOpen = activePanel === "director";
  const characterOpen = activePanel === "character";
  const groupOpen = activePanel === "group";
  const exportOpen = activePanel === "export";
  const hasOpenPanel = activePanel !== null;

  // Per-panel setters that accept boolean | toggle callback (preserves the
  // original signature used in onClick / onClose callbacks).
  const setMemoryOpen = useCallback(
    (v: boolean | ((prev: boolean) => boolean)) =>
      setActivePanel((p) => ((typeof v === "function" ? v(p === "memory") : v) ? "memory" : null)),
    [],
  );
  const setInventoryOpen = useCallback(
    (v: boolean | ((prev: boolean) => boolean)) =>
      setActivePanel((p) => ((typeof v === "function" ? v(p === "inventory") : v) ? "inventory" : null)),
    [],
  );
  const setQuestsOpen = useCallback(
    (v: boolean | ((prev: boolean) => boolean)) =>
      setActivePanel((p) => ((typeof v === "function" ? v(p === "quests") : v) ? "quests" : null)),
    [],
  );
  const setDirectorOpen = useCallback(
    (v: boolean | ((prev: boolean) => boolean)) =>
      setActivePanel((p) => ((typeof v === "function" ? v(p === "director") : v) ? "director" : null)),
    [],
  );
  const setCharacterOpen = useCallback(
    (v: boolean | ((prev: boolean) => boolean)) =>
      setActivePanel((p) => ((typeof v === "function" ? v(p === "character") : v) ? "character" : null)),
    [],
  );
  const setGroupOpen = useCallback(
    (v: boolean | ((prev: boolean) => boolean)) =>
      setActivePanel((p) => ((typeof v === "function" ? v(p === "group") : v) ? "group" : null)),
    [],
  );
  const setExportOpen = useCallback(
    (v: boolean | ((prev: boolean) => boolean)) =>
      setActivePanel((p) => ((typeof v === "function" ? v(p === "export") : v) ? "export" : null)),
    [],
  );

  // Android back button: close panels first, then navigate back
  useAndroidBack({ hasOpenPanel }, () => {
    if (exportOpen) setActivePanel(null);
    else if (memoryOpen) setActivePanel(null);
    else if (inventoryOpen) setActivePanel(null);
    else if (questsOpen) setActivePanel(null);
    else if (characterOpen) setActivePanel(null);
    else if (directorOpen) setActivePanel(null);
    else if (groupOpen) setActivePanel(null);
    else navigate(-1);
  });

  return {
    activePanel,
    openPanel,
    closePanel,
    togglePanel,
    // Convenience booleans
    memoryOpen,
    inventoryOpen,
    questsOpen,
    directorOpen,
    characterOpen,
    groupOpen,
    exportOpen,
    hasOpenPanel,
    // Legacy per-panel setters for direct boolean/toggle control
    setMemoryOpen,
    setInventoryOpen,
    setQuestsOpen,
    setDirectorOpen,
    setCharacterOpen,
    setGroupOpen,
    setExportOpen,
  };
}

